class Solution:
    def threeEqualParts(self, arr):
        n = len(arr)
        def value(i, j):
            # binary value of arr[i:j]
            v = 0
            for k in range(i, j):
                v = v * 2 + arr[k]
            return v
        for i in range(n - 2):
            for j in range(i + 2, n):
                if value(0, i + 1) == value(i + 1, j) == value(j, n):
                    return [i, j]
        return [-1, -1]

