class Solution:
    def threeEqualParts(self, arr):
        n = len(arr)
        ones = sum(arr)
        if ones % 3 != 0:
            return [-1, -1]
        if ones == 0:
            return [0, 2]
        k = ones // 3
        positions = [idx for idx, v in enumerate(arr) if v == 1]
        first = positions[0]
        second = positions[k]
        third = positions[2 * k]
        suffix_zeros = n - 1 - positions[-1]
        length = n - third
        if first + length > second or second + length > third:
            return [-1, -1]
        for d in range(length):
            if arr[first + d] != arr[second + d] or arr[second + d] != arr[third + d]:
                return [-1, -1]
        return [first + length - 1, second + length]

