var threeEqualParts = function(arr) {
    const n = arr.length;
    let ones = 0;
    for (const v of arr) ones += v;
    if (ones % 3 !== 0) return [-1, -1];
    if (ones === 0) return [0, 2];
    const k = ones / 3;
    const positions = [];
    for (let i = 0; i < n; i++) if (arr[i] === 1) positions.push(i);
    const first = positions[0];
    const second = positions[k];
    const third = positions[2 * k];
    const length = n - third;
    if (first + length > second || second + length > third) return [-1, -1];
    for (let d = 0; d < length; d++) {
        if (arr[first + d] !== arr[second + d] || arr[second + d] !== arr[third + d]) {
            return [-1, -1];
        }
    }
    return [first + length - 1, second + length];
};
